record.field:
{
  "type": "object",
  "title": "PropertyOptionsResponse",
  "additionalProperties": false,
  "properties": {
    "source_medium": {
      "type": "array",
      "description": "Options accepted by the source_medium API field.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      },
      "example": [
        {
          "value": "website",
          "label": "Website"
        }
      ]
    },
    "zoning": {
      "type": "array",
      "description": "Options accepted by the zoning API field.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      },
      "example": [
        {
          "value": "residential",
          "label": "Residential"
        }
      ]
    },
    "property_purpose": {
      "type": "array",
      "description": "Options accepted by property_purpose.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      }
    },
    "property_status": {
      "type": "array",
      "description": "Options accepted by property_status.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      }
    },
    "property_situation": {
      "type": "array",
      "description": "Options accepted by property_situation.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "Desocupado"
          },
          "label": {
            "type": "string",
            "example": "Desocupado"
          }
        }
      },
      "example": [
        {"value": "Não Informado", "label": "Não Informado"},
        {"value": "Desocupado", "label": "Desocupado"},
        {"value": "Ocupado", "label": "Ocupado"},
        {"value": "Reservado", "label": "Reservado"},
        {"value": "Em construção", "label": "Em construção"},
        {"value": "Lançamento", "label": "Lançamento"},
        {"value": "Novo", "label": "Novo"}
      ]
    },
    "condition": {
      "type": "array",
      "description": "Options accepted by condition.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      }
    },
    "activity_notification": {
      "type": "array",
      "description": "Options accepted by activity_notification.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      }
    },
    "sign_type": {
      "type": "array",
      "description": "Options accepted by sign_type.",
      "items": {
        "type": "object",
        "title": "PropertyOptionItem",
        "properties": {
          "value": {
            "type": "string",
            "example": "website"
          },
          "label": {
            "type": "string",
            "example": "Website"
          }
        }
      }
    },
    "multi_value_fields": {
      "type": "array",
      "description": "Fields that accept multiple values or arrays.",
      "items": {
        "type": "object",
        "properties": {
          "field": {
            "type": "string",
            "example": "tags"
          },
          "type": {
            "type": "string",
            "example": "many2many"
          },
          "accepted_values": {
            "type": "array",
            "items": {
              "type": "string"
            },
            "example": [
              "string",
              "integer"
            ]
          },
          "options_endpoint": {
            "type": "string",
            "nullable": true,
            "example": "/api/v1/tags"
          }
        }
      }
    },
    "related_options": {
      "type": "object",
      "description": "Existing master-data endpoints for related property fields.",
      "additionalProperties": {
        "type": "string"
      },
      "example": {
        "property_type_id": "/api/v1/property-types",
        "location_type_id": "/api/v1/location-types",
        "state_id": "/api/v1/states",
        "tags": "/api/v1/tags",
        "amenities": "/api/v1/amenities"
      }
    }
  }
}

{
  "type": "object",
  "title": "PropertyListResponse",
  "additionalProperties": false,
  "properties": {
    "success": {
      "type": "boolean",
      "description": "Operation status.",
      "example": true
    },
    "data": {
      "type": "array",
      "description": "Paginated properties.",
      "items": {
        "type": "object",
        "title": "PropertyResponse",
        "additionalProperties": true,
        "properties": {
          "id": {
            "type": "integer",
            "description": "Property ID.",
            "example": 17
          },
          "name": {
            "type": "string",
            "description": "Property name.",
            "example": "Casa Moderna em Sao Jose dos Campos"
          },
          "description": {
            "type": "string",
            "description": "Property description.",
            "example": "<p>Descricao atualizada</p>"
          },
          "price": {
            "type": "number",
            "description": "Sale price.",
            "example": 850000
          },
          "price_formatted": {
            "type": "string",
            "description": "Localized sale price.",
            "example": "R$ 850.000,00"
          },
          "status": {
            "type": "string",
            "description": "Legacy alias for property_status.",
            "example": "available"
          },
          "property_status": {
            "type": "string",
            "description": "Property status enum.",
            "example": "available"
          },
          "for_sale": {
            "type": "boolean",
            "description": "Available for sale.",
            "example": true
          },
          "for_rent": {
            "type": "boolean",
            "description": "Available for rent.",
            "example": false
          },
          "accepts_financing": {
            "type": "boolean",
            "description": "Accepts financing.",
            "example": true
          },
          "fgts": {
            "type": "object",
            "readOnly": true,
            "description": "FGTS data and computed eligibility for this property.",
            "properties": {
              "accepts_fgts": {"type": "boolean", "example": true},
              "used_fgts": {"type": "boolean", "example": true},
              "last_usage_date": {"type": "string", "format": "date", "nullable": true, "example": "2024-03-10"},
              "eligible_from": {"type": "string", "format": "date", "nullable": true, "example": "2027-03-11"},
              "eligible_now": {"type": "boolean", "example": false},
              "usage_notes": {"type": "string", "nullable": true, "example": "Uso identificado na matricula anterior"}
            }
          },
          "property_type": {
            "type": "object",
            "nullable": true,
            "properties": {
              "id": {
                "type": "integer",
                "description": "Property type ID.",
                "example": 2
              },
              "name": {
                "type": "string",
                "description": "Property type name.",
                "example": "House"
              }
            }
          },
          "agent": {
            "type": "object",
            "nullable": true,
            "properties": {
              "id": {
                "type": "integer",
                "description": "Agent ID.",
                "example": 3
              },
              "name": {
                "type": "string",
                "description": "Agent name.",
                "example": "Carmen Rodriguez"
              },
              "email": {
                "type": "string",
                "format": "email",
                "example": "carmen@example.com"
              }
            }
          },
          "owner": {
            "type": "object",
            "nullable": true,
            "description": "Property owner serialized from owner_id relationship.",
            "properties": {
              "id": {"type": "integer", "example": 9},
              "name": {"type": "string", "example": "Maria Proprietaria"},
              "email": {"type": "string", "format": "email", "example": "maria@example.com"},
              "phone": {"type": "string", "example": "1130001000"},
              "mobile": {"type": "string", "example": "11999990000"},
              "whatsapp": {"type": "string", "example": "11988887777"},
              "partner_id": {"type": "integer", "nullable": true, "example": 44},
              "address": {"type": "string", "example": "Rua do Proprietario"},
              "city": {"type": "string", "example": "Sao Paulo"},
              "state": {
                "type": "object",
                "nullable": true,
                "properties": {
                  "id": {"type": "integer", "example": 35},
                  "name": {"type": "string", "example": "Sao Paulo"},
                  "code": {"type": "string", "example": "SP"}
                }
              },
              "zip_code": {"type": "string", "example": "01000-000"}
            }
          },
          "company": {
            "type": "object",
            "properties": {
              "id": {
                "type": "integer",
                "nullable": true,
                "example": 1
              },
              "name": {
                "type": "string",
                "nullable": true,
                "example": "Quicksol Real Estate"
              }
            }
          },
          "address": {
            "type": "object",
            "properties": {
              "street": {
                "type": "string",
                "description": "Street.",
                "example": "Rua das Flores"
              },
              "number": {
                "type": "string",
                "description": "Street number.",
                "example": "123"
              },
              "complement": {
                "type": "string",
                "description": "Complement.",
                "example": "apto 12"
              },
              "neighborhood": {
                "type": "string",
                "description": "Neighborhood.",
                "example": "Jardim Aquarius"
              },
              "city": {
                "type": "string",
                "description": "City.",
                "example": "Sao Jose dos Campos"
              },
              "state": {
                "type": "object",
                "nullable": true,
                "properties": {
                  "id": {
                    "type": "integer",
                    "description": "State ID.",
                    "example": 25
                  },
                  "name": {
                    "type": "string",
                    "description": "State name.",
                    "example": "Sao Paulo"
                  },
                  "code": {
                    "type": "string",
                    "description": "State code.",
                    "example": "SP"
                  }
                }
              },
              "zip_code": {
                "type": "string",
                "description": "ZIP/CEP.",
                "example": "12245-000"
              },
              "location_type": {
                "type": "object",
                "nullable": true,
                "properties": {
                  "id": {
                    "type": "integer",
                    "description": "Location type ID.",
                    "example": 1
                  },
                  "name": {
                    "type": "string",
                    "description": "Location type name.",
                    "example": "Urbano"
                  },
                  "code": {
                    "type": "string",
                    "description": "Location type code.",
                    "example": "urban"
                  }
                }
              }
            }
          },
          "features": {
            "type": "object",
            "properties": {
              "bedrooms": {
                "type": "integer",
                "description": "Bedroom count.",
                "example": 4
              },
              "suites": {
                "type": "integer",
                "description": "Suite count.",
                "example": 1
              },
              "bathrooms": {
                "type": "integer",
                "description": "Bathroom count.",
                "example": 3
              },
              "parking_spaces": {
                "type": "integer",
                "description": "Parking space count.",
                "example": 2
              },
              "area": {
                "type": "number",
                "description": "Built area.",
                "example": 180.5
              },
              "total_area": {
                "type": "number",
                "description": "Total area.",
                "example": 250
              }
            }
          },
          "created_date": {
            "type": "string",
            "format": "date-time",
            "nullable": true,
            "example": "2026-05-04T12:45:00.123456"
          },
          "updated_date": {
            "type": "string",
            "format": "date-time",
            "nullable": true,
            "example": "2026-05-04T13:10:00.123456"
          },
          "source_medium": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to origin_media.",
            "example": "website"
          },
          "send_activities_to_owner": {
            "type": "boolean",
            "description": "Whether property activities should be sent to the owner.",
            "example": true
          },
          "search_street": {
            "type": "string",
            "nullable": true,
            "description": "Search street alias. Mapped to street.",
            "example": "Rua das Flores"
          },
          "registered_by": {
            "type": "string",
            "nullable": true,
            "description": "User or source that registered the property.",
            "example": "CRM Import"
          },
          "alternative_reference": {
            "type": "string",
            "nullable": true,
            "description": "Alternative external reference.",
            "example": "ALT-2026-0001"
          },
          "intention": {
            "type": "string",
            "nullable": true,
            "description": "Owner intention.",
            "example": "sale"
          },
          "iptu_payment_condition": {
            "type": "string",
            "nullable": true,
            "description": "IPTU payment condition.",
            "example": "owner_pays"
          },
          "iptu_value": {
            "type": "string",
            "nullable": true,
            "description": "IPTU value as mapped by the source spreadsheet.",
            "example": "250.00"
          },
          "rental_guarantee_insurance": {
            "type": "string",
            "nullable": true,
            "description": "Rental guarantee insurance information.",
            "example": "Porto Seguro"
          },
          "fire_insurance": {
            "type": "string",
            "nullable": true,
            "description": "Fire insurance information.",
            "example": "included"
          },
          "exclusivity": {
            "type": "boolean",
            "description": "Whether this property is exclusive.",
            "example": true
          },
          "property_situation": {
            "type": "string",
            "nullable": true,
            "description": "Property situation. Accepted values are documented in GET /api/v1/properties/options.",
            "enum": ["Não Informado", "Desocupado", "Ocupado", "Reservado", "Em construção", "Lançamento", "Novo"],
            "example": "Desocupado"
          },
          "year_of_renovation": {
            "type": "string",
            "nullable": true,
            "description": "Renovation year returned as string.",
            "example": "2024"
          },
          "zoning": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to zoning_type.",
            "example": "ZR2"
          },
          "internal_comments": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to internal_notes.",
            "example": "Owner prefers weekday visits."
          },
          "tags": {
            "type": "array",
            "description": "Property tag names.",
            "items": {
              "type": "string"
            },
            "example": [
              "premium",
              "sea-view"
            ]
          },
          "key_location": {
            "type": "string",
            "nullable": true,
            "description": "Property key location.",
            "example": "Concierge desk"
          },
          "property_images": {
            "type": "array",
            "description": "Property image metadata. Binary content is never returned inline.",
            "items": {
              "type": "object",
              "title": "AttachmentMetadata",
              "additionalProperties": false,
              "properties": {
                "id": {
                  "type": "integer",
                  "description": "Attachment record ID.",
                  "example": 10
                },
                "name": {
                  "type": "string",
                  "description": "Attachment display name.",
                  "example": "fachada.jpg"
                },
                "mimetype": {
                  "type": "string",
                  "description": "Detected MIME type.",
                  "example": "image/jpeg"
                },
                "size": {
                  "type": "integer",
                  "description": "Decoded binary size in bytes.",
                  "example": 24816
                },
                "download_url": {
                  "type": "string",
                  "description": "Relative URL to download the attachment content.",
                  "example": "/web/content/real.estate.property.photo/10/image?download=true"
                }
              }
            }
          },
          "advertise": {
            "type": "boolean",
            "description": "Mapped to publish_website.",
            "example": true
          },
          "featured_property": {
            "type": "boolean",
            "description": "Mapped to publish_featured.",
            "example": false
          },
          "virtual_tour": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to virtual_tour_url.",
            "example": "https://example.com/tour/property-17"
          },
          "sign_on_site": {
            "type": "boolean",
            "description": "Mapped to has_sign.",
            "example": true
          },
          "super_featured": {
            "type": "boolean",
            "description": "Mapped to publish_super_featured.",
            "example": false
          },
          "youtube_video": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to youtube_video_url.",
            "example": "https://youtube.com/watch?v=abc123"
          },
          "commission_type": {
            "type": "string",
            "nullable": true,
            "description": "Commission type.",
            "example": "percentage"
          },
          "captured_intention": {
            "type": "string",
            "nullable": true,
            "description": "Captured business intention.",
            "example": "sell"
          },
          "included_in_commission_date": {
            "type": "string",
            "format": "date",
            "nullable": true,
            "description": "Date when included in commission workflow.",
            "example": "2026-05-04"
          },
          "commercial_condition": {
            "type": "string",
            "nullable": true,
            "description": "Commercial condition free-text value.",
            "example": "Condição comercial padrão"
          },
          "iptu_code": {
            "type": "string",
            "nullable": true,
            "description": "IPTU code.",
            "example": "IPTU-123456"
          },
          "registration_number": {
            "type": "string",
            "nullable": true,
            "description": "Mapped to matricula_number.",
            "example": "MAT-98765"
          },
          "electricity_network_code": {
            "type": "string",
            "nullable": true,
            "description": "Electricity utility code.",
            "example": "ENEL-001122"
          },
          "water_network_code": {
            "type": "string",
            "nullable": true,
            "description": "Water utility code.",
            "example": "SABESP-998877"
          },
          "titles_rights": {
            "type": "string",
            "nullable": true,
            "description": "Titles and rights notes.",
            "example": "Owner holds full title rights."
          },
          "approved_environmental_agency": {
            "type": "boolean",
            "description": "Whether the environmental agency approval exists.",
            "example": true
          },
          "approved_project": {
            "type": "boolean",
            "description": "Whether the project is approved.",
            "example": true
          },
          "documentation_observations": {
            "type": "string",
            "nullable": true,
            "description": "Documentation observations.",
            "example": "Registration pending registry update."
          },
          "property_files": {
            "type": "array",
            "description": "Property document metadata. Binary content is never returned inline.",
            "items": {
              "type": "object",
              "title": "AttachmentMetadata",
              "additionalProperties": false,
              "properties": {
                "id": {
                  "type": "integer",
                  "description": "Attachment record ID.",
                  "example": 10
                },
                "name": {
                  "type": "string",
                  "description": "Attachment display name.",
                  "example": "fachada.jpg"
                },
                "mimetype": {
                  "type": "string",
                  "description": "Detected MIME type.",
                  "example": "image/jpeg"
                },
                "size": {
                  "type": "integer",
                  "description": "Decoded binary size in bytes.",
                  "example": 24816
                },
                "download_url": {
                  "type": "string",
                  "description": "Relative URL to download the attachment content.",
                  "example": "/web/content/real.estate.property.photo/10/image?download=true"
                }
              }
            }
          }
        }
      }
    },
    "count": {
      "type": "integer",
      "description": "Number of items in this page.",
      "example": 10
    },
    "total": {
      "type": "integer",
      "description": "Total matching records.",
      "example": 50
    },
    "limit": {
      "type": "integer",
      "description": "Page size.",
      "example": 20
    },
    "offset": {
      "type": "integer",
      "description": "Pagination offset.",
      "example": 0
    },
    "_links": {
      "type": "object",
      "additionalProperties": {
        "type": "string"
      },
      "example": {
        "self": "/api/v1/properties?company_ids=1&limit=20&offset=0",
        "next": "/api/v1/properties?company_ids=1&limit=20&offset=20"
      }
    }
  }
}

{
  "type": "object",
  "title": "PropertyCreate",
  "required": [
    "session_id",
    "name",
    "property_type_id",
    "area",
    "zip_code",
    "state_id",
    "city",
    "street",
    "street_number",
    "location_type_id"
  ],
  "additionalProperties": true,
  "properties": {
    "session_id": {
      "type": "string",
      "description": "Session ID for fingerprint validation on POST/PUT/PATCH requests.",
      "example": "{{session_id}}"
    },
    "name": {
      "type": "string",
      "description": "Property name.",
      "example": "Casa Moderna em Sao Jose dos Campos"
    },
    "property_type_id": {
      "type": "integer",
      "description": "Property type ID.",
      "example": 2
    },
    "area": {
      "type": "number",
      "description": "Built area in square meters.",
      "example": 180.5
    },
    "zip_code": {
      "type": "string",
      "description": "ZIP/CEP code.",
      "example": "12245-000"
    },
    "state_id": {
      "type": "integer",
      "description": "State ID.",
      "example": 25
    },
    "city": {
      "type": "string",
      "description": "City name.",
      "example": "Sao Jose dos Campos"
    },
    "street": {
      "type": "string",
      "description": "Street name.",
      "example": "Rua das Flores"
    },
    "street_number": {
      "type": "string",
      "description": "Street number.",
      "example": "123"
    },
    "location_type_id": {
      "type": "integer",
      "description": "Location type ID.",
      "example": 1
    },
    "description": {
      "type": "string",
      "description": "Property description.",
      "example": "<p>Casa reformada em excelente localizacao</p>"
    },
    "price": {
      "type": "number",
      "description": "Sale price.",
      "example": 850000
    },
    "rent_price": {
      "type": "number",
      "description": "Rent price.",
      "example": 4200
    },
    "property_status": {
      "type": "string",
      "description": "Property status.",
      "example": "available"
    },
    "property_purpose": {
      "type": "string",
      "description": "Property purpose.",
      "example": "residential"
    },
    "num_rooms": {
      "type": "integer",
      "description": "Number of bedrooms.",
      "example": 4
    },
    "num_suites": {
      "type": "integer",
      "description": "Number of suites.",
      "example": 1
    },
    "num_bathrooms": {
      "type": "integer",
