            "example": "fachada.jpg"
          },
          "mimetype": {
            "type": "string",
            "description": "Detected MIME type.",
            "example": "image/jpeg"
          },
          "size": {
            "type": "integer",
            "description": "Decoded binary size in bytes.",
            "example": 24816
          },
          "download_url": {
            "type": "string",
            "description": "Relative URL to download the attachment content.",
            "example": "/web/content/real.estate.property.photo/10/image?download=true"
          }
