{
  "type": "object",
  "title": "PropertyAttachmentUpload",
  "description": "multipart/form-data — send as form field named 'file'.",
  "required": ["file", "attachment_type"],
  "properties": {
    "file": {
      "type": "string",
      "format": "binary",
      "description": "The file to upload. MIME type is validated from magic bytes."
    },
    "attachment_type": {
      "type": "string",
      "enum": ["image", "document"],
      "description": "Type discriminator — validated server-side against MIME whitelist."
    }
  }
}

{
  "type": "object",
  "title": "PropertyAttachmentUploadResponse",
  "additionalProperties": false,
  "properties": {
    "status": {
      "type": "string",
      "example": "success"
    },
    "data": {
      "type": "object",
      "title": "AttachmentDetail",
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "integer",
          "description": "Attachment record ID.",
          "example": 42
        },
        "name": {
          "type": "string",
          "description": "Sanitized file name.",
          "example": "fachada.jpg"
        },
        "mimetype": {
          "type": "string",
          "description": "Detected MIME type (from magic bytes).",
          "example": "image/jpeg"
        },
        "size": {
          "type": "integer",
          "description": "File size in bytes.",
          "example": 204800
        },
        "attachment_type": {
          "type": "string",
          "description": "Classification: image or document.",
          "enum": ["image", "document"],
          "example": "image"
        },
        "download_url": {
          "type": "string",
          "description": "Relative URL to download the attachment.",
          "example": "/api/v1/properties/17/attachments/42/download"
        },
        "_links": {
          "type": "object",
          "description": "HATEOAS navigation links.",
          "properties": {
            "self": {
              "type": "string",
              "example": "/api/v1/properties/17/attachments/42"
            },
            "download": {
              "type": "string",
              "example": "/api/v1/properties/17/attachments/42/download"
            }
          }
        }
      }
    }
  }
}

